insert into factions (id, campaign_id, slug, name, type, goal, resources) values ('2d88a0a3-87bf-4a9f-aea7-3f874f9afa38', '3d94bb9a-3995-452f-9e20-371c6c697443', 'order-of-the-bone', 'Order of the Bone', 'Cult', '- Secretive, underground cult that believes turning to stone is not death, but a means to ascension. To them, flesh is a temporary burden — pain, hunger, fear, and grief made manifest — and stone is freedom from all of it.
- They teach that when the body stills, the soul is released from the cycle of seasons and suffering, able to pass into a higher, eternal state. Shun’Aush, they claim, did not perish — he shed his flesh and became something greater. Those who turn to stone follow in his path.
- The Serpent’s Sickness is not a curse in their eyes.
- They are opposed to the Crimson Lady’s cure.
- They carry bone dust with them and provide it to converted followers.
- Led by Mother Stillroot, a cloaked Fungril.', NULL);
insert into factions (id, campaign_id, slug, name, type) values ('dd9efaa3-65a5-430d-8d8f-2b9e3005d54a', '3d94bb9a-3995-452f-9e20-371c6c697443', 'unaligned', 'Unaligned', 'Independent');

-- legacy divinities/mmm8oqrbu4vjh2vn5lh
insert into divinities (id, campaign_id, slug, name, domain, dogma, worshippers) values ('bee7104d-6568-4c04-8cbc-1ef0e3b547e9', '3d94bb9a-3995-452f-9e20-371c6c697443', 'lirath', 'Lirath', 'The Shadow Trickster', 'Lirath is a god of mischief, illusions, and cleverness. Known for stirring chaos and brightening otherwise dull days with his unpredictable antics, he thrives on wit and cunning. Lirath often plays pranks on other gods and mortals alike, using illusions and trickery to teach lessons or simply to entertain himself. Despite his mischievous nature, he is revered for his intelligence and resourcefulness, often guiding those who seek clever solutions to complex problems. His presence is subtle yet powerful, often felt in moments of surprise or when things seem to take an unexpected turn.', NULL);
-- legacy divinities/mmm8tigl7bp068kf0ja
insert into divinities (id, campaign_id, slug, name, domain, dogma, worshippers) values ('f527736e-8ee4-4e17-ab7c-9d597710eec2', '3d94bb9a-3995-452f-9e20-371c6c697443', 'nikta', 'Nikta', 'The Shepard of Seasons', 'Nikta controls the changing of seasons based on which eye she is gazing on the land from
The Sowing Eye
• Governs growth, renewal, fertility, and the turning of spring into summer.
• It’s what allows new life to emerge after decay.
• Its light is warm, green-gold, and nurturing — the “breath” of nature itself.

The Reaping Eye
• Governs decay, dormancy, death, and the turn from autumn into winter.
• It allows old life to pass, feeding the soil for the next bloom.
• Its light is silver and cold, but not evil — it is the necessary end.

Archmage Phylax stole Nikta''s reaping eye to increase the growth of Haven''s flower fields.', NULL);

-- legacy locations/mmm2tv4o0wrzmas9xy3n
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('7f963150-a8dc-4686-9655-178edad7b011', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'alula', 'Alula', 'settlement', ARRAY['City']::text[], NULL, 'Treetop Village. The village serves as neutral territory between Haven and Fanewick.', '<p>A small village in the treetops of The Unsleeping Wood. It is an independent village who has, so far, been able to avoid choosing sides in the war. Havenites and Wicklings use the village as neutral ground to meet with leaders of both sides.</p><p>Many treetops are all connected by rope bridges. There is a large municipal platform that serves as the center of the village with bridges leading in all directions to other groups of structures in the other trees. All made from locally sourced wood and materials that blend in perfectly to the surrounding area.</p><h3>Points of Interest</h3><p>Treetop Tavern -  Loud and vibrant environment. People of all ancestries laughing and yelling in excitement and intoxication. A tree rises up through the center of the tavern. The bar is a full circle around the tree. There are many tables arranged around the bar and against the exterior facing wall. Above the tavern the structure rises up around a larger tree with inn rooms.</p><p>Timber''s Trinkets - Small merchant shop run by Timber, a halfling. The shop currently is not well stocked because trade into the area has been blocked by the Witherwild. Once the players help Elara decipher the stone cipher, traders can make it to Alula safely with more goods.</p>');
-- legacy locations/mmm5ucycibdp2johrmq
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('e8edda15-4277-4d48-b102-0b42bed9a779', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'bogs-of-despair', 'Bogs of Despair', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>The Bogs of Despair is said to be the location where Shun''Aush''s heart finally decayed after the Havenites slew him. Those who enter the Bogs of Despair rarely emerge, forever lost in their sorrow. Sometimes at night you can hear the faint desperate cries of its lost souls.</p>');
-- legacy locations/mmm5vrj8vv4k4rcx4u
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('37f15a38-9d9e-4b1c-942b-c711a51903dc', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-great-spliff', 'The Great Spliff', 'settlement', ARRAY['Town']::text[], NULL, NULL, '<p>This ancient pine is revered by the Galapa and other Wildborne creatures as a sacred site. They believe the tree is a conduit to the spirit world and that its needles possess powerful healing properties. The Great Spliff is also a haven for refugees fleeing the Witherwild, offering a temporary sanctuary amidst the chaos.</p><p>Herbtle''s hometown</p>');
-- legacy locations/mmm5wu2x2y58o7knp9i
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('b0ea589c-11ec-4435-925a-78119de686a6', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-unsleeping-wood', 'The Unsleeping Wood', 'wilderness', ARRAY['Region']::text[], NULL, NULL, '<p>A large forest inhabited by many races of wicklings. </p>');
-- legacy locations/mmm76y9lcpfuxlddzi
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('f38213a5-05f0-4120-9b0e-fc156b3f69aa', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-riverwalkers-hunting-ground', 'The Riverwalkers Hunting Ground', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>This area is the site of intense conflict between Haven and Fanewick, as the Crimson Lady grows here in abundance. Havenite patrols regularly venture into the area to harvest the flower, leading to frequent skirmishes with rebel Wicklings.</p>');
-- legacy locations/mmm78cykh41vkqeru2
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('c304fc10-2959-43a2-b955-997abff9c3a1', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'tailspire-crags', 'Tailspire Crags', 'landmark', ARRAY['Ruins']::text[], NULL, NULL, '<p>Legends say that the two pillars were once connected, forming a gateway to another realm. A powerful earthquake shattered the bridge, severing the connection and unleashing a surge of magical energy that warped the surrounding landscape. The Witherwild acts differently here. Instead of attacking recklessly it protects the crags and any attempt to repair the connection.</p>');
-- legacy locations/mmm79pfynvtwx6li1b7
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('17c12811-1fe8-43c7-a6e7-da79c7b11058', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-carnivorous-divide', 'The Carnivorous Divide', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>Plants compete for dominance, evolving into monstrous, carnivorous forms. The air is thick with pollen and spores, causing hallucinations and paranoia.</p>');
-- legacy locations/mmm7ah0let7h1tg7vwn
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('1ef92619-6e86-4e36-9260-6371e4de5bc4', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-stones-of-cassema', 'The Stones of Cassema', 'landmark', ARRAY['Ruins']::text[], NULL, NULL, '<p>These stones are said to be left by the Ancients. They hum with a faint energy, and some say they can be used to communicate with the spirits of the land. However, tampering with the stones is said to anger the divinities and invite misfortune.</p>');
-- legacy locations/mmm7bk5u5jtndaafxhp
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('7a08756e-2b12-48ec-be13-463a077c783a', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'the-fields-of-unceasing-song', 'The Fields of Unceasing Song', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>The singing is said to be the ghost of a Wickling woman who was betrayed by her Havenite lover. The wind carried her sorrowful melody across the fields. The winds can also make travelers entranced.</p>');
-- legacy locations/mmm7cm0bjc8qqebduz9
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('789e0503-ff44-4660-929d-524baee1261d', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'rot-hollow', 'Rot Hollow', 'landmark', ARRAY['Mountain']::text[], NULL, NULL, '<p>The crack in the mountainside is believed to be a scar left by Shun''Aush''s death, a wound in the earth that never truly healed. rebel Wicklings built a passage into the mountain to attempt to cross the border unseen.</p>');
-- legacy locations/mmm7dt6qvpundjlnvks
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('7fb21771-74b5-4c67-9535-1081ff7055c3', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'cackling-moor', 'Cackling Moor', 'settlement', ARRAY['Town']::text[], NULL, NULL, '<p>A potent area full of fungi that is only habitable by Fungril. The spores from the mushrooms create hysteria in the unwary. The faint divinity Oove has been known to act as protector of this land.</p><p>N''Lirk''s home</p>');
-- legacy locations/mmm7f64luci8g3mbqle
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('3bb1c91c-c091-4b59-aca4-d9b83ce817bb', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'stolen-fen', 'Stolen Fen', 'settlement', ARRAY['Town']::text[], NULL, NULL, '<p>A town of Wicklings who were forced to pledge loyalty to Haven in exchange for protection from the Witherwild. They are viewed with suspicion by both sides, caught between their former allegiances and their new obligations.</p>');
-- legacy locations/mmm7fmwrkhywhlf0wvd
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('5440c14a-6a3c-4f8b-8c55-ef488fa7b275', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'shun-aush', 'Shun’Aush', 'settlement', ARRAY['City']::text[], NULL, NULL, '<p>The city is a haunting reminder of Haven''s past transgressions. The statues of petrified citizens serve as a constant warning, a symbol of the consequences of defying the Faint Divinities. The air is still filled with the bone dust of Shun’Aush so the inhabitants who still live there must wear ventilators when outside.</p>');
-- legacy locations/mmm7gjpquk4b1rd23fk
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('82df0752-c9d5-414f-8c53-3cf194647ee7', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'low-passage', 'Low Passage', 'settlement', ARRAY['Town']::text[], NULL, NULL, '<p>This town is a vital trade hub for Haven, connecting the city to the southern regions. It is also a staging ground for Havenite patrols venturing into the Riverwalkers Hunting Ground to harvest the Crimson Lady. Tensions are high in Low Passage, as the town is constantly threatened by both the Serpent''s Sickness and attacks from Fanewick.</p>');
-- legacy locations/mmm7h61umb6hz3axysj
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('ea67541c-2d24-4a18-a4ff-cffaee6f1cf8', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'keener-s-pike', 'Keener''s Pike', 'landmark', ARRAY['Mountain']::text[], NULL, NULL, '<p>This mountain range is rich in minerals and resources, making it a valuable asset for Haven. However, the mountains are also home to dangerous creatures and hidden ruins, remnants of a civilization that predates both Haven and Fanewick. Havenites who venture into the mountains often disappear without a trace, fueling rumors of ancient curses and vengeful spirits.</p>');
-- legacy locations/mmm7hj9tsm81i6j68mi
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('a137a81b-d38b-42b5-9c0d-ac43fc553c80', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'qavvik-s-tower', 'Qavvik''s Tower', 'landmark', ARRAY['Ruins']::text[], NULL, NULL, '<p>A desolate place, shunned by both sides. The reason for the barren land around the tower is a mystery, but some say it was once a site of a terrible magical experiment to rid the region of the Witherwild that went awry. The tower is now haunted by restless spirits and strange phenomena, making it a dangerous and unsettling place to visit.</p>');
-- legacy locations/mmm7itmq15sdpwnhuxt
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('7d68dc4d-601a-4ac2-865b-d08e02a09cf7', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'gor-s-descent', 'Gor’s Descent', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>Path down the mountain that connects the barren area to the wilds surrounding The Somnolent Shore.</p>');
-- legacy locations/mmm7jorh4yeeek3h46d
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('a0e5050b-1c4c-4d58-ad3f-17b0e342db0e', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'silver-sage', 'Silver Sage', 'settlement', ARRAY['Town']::text[], NULL, NULL, '<p>A mysterious city founded by Havenites seeking spiritual enlightenment. They claim to have unlocked the secrets of the Ancients and have developed unique magical practices that are unlike anything else in the region. Silver Sage is largely isolated from the rest of Haven, and its inhabitants are viewed with suspicion by those who cling to traditional beliefs.</p>');
-- legacy locations/mmm7ka4pgam3r2z4k7
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('760ec744-2634-42bb-8c6c-74109d86ae8a', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'the-pond-of-lost-hope', 'The Pond of Lost Hope', 'wilderness', ARRAY['Wilderness']::text[], NULL, NULL, '<p>This pond is said to be a window to another realm. Those who enter the pond with a pure heart and a strong desire may be granted a glimpse of the divine, but those who are driven by greed or malice will be consumed by the darkness within. Many have sought the pond, hoping for a miracle, but most simply vanish, their hopes forever lost in its depths.</p>');
-- legacy locations/mmm7lh4bapypl1i3tp4
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('deb0f4f8-6b37-41f2-9e62-a41e78c69136', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'crystal-bridge', 'Crystal Bridge', 'building', ARRAY['Outpost']::text[], NULL, NULL, '<p>The fortress is built atop Fire Falls. It is a symbol of Haven''s technological prowess and military might, a testament to their determination to control the resources of the region. The bridge is heavily guarded and is said to be protected by powerful magical wards, making it a difficult target for attack.</p>');
-- legacy locations/mmm83waw9wgdbqduw6q
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('d451fac3-52f0-441c-8435-c5e13c008165', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'seagloam-cave', 'Seagloam Cave', 'dungeon', ARRAY['Cave']::text[], NULL, NULL, '<p>The crystals that line the cave are said to amplify magical energy, making it a valuable resource for Havenite sorcerers. However, the cave is also home to strange and dangerous creatures, mutated by the magical energies within. Those who venture into Seagloam Cave risk not only their lives but also their sanity.</p>');
-- legacy locations/mmm84nz5jwco7yv9zum
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('b8aa941d-b82b-411b-aaf6-641ee093b3aa', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'the-somnolent-shore', 'The Somnolent Shore', 'landmark', ARRAY['Beach/Waterfront']::text[], NULL, NULL, '<p>The waters here are said to possess calming properties, lulling those who linger too long into a deep and dreamless sleep. The shore is a popular destination for Havenites seeking respite from the horrors of the Serpent''s Sickness.</p>');
-- legacy locations/mmm854pqhfai2esqmp9
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('e6abcca9-455e-41db-8def-00b743708d32', '3d94bb9a-3995-452f-9e20-371c6c697443', '54165b88-6139-43c2-be0c-3b172c79cebb', 'the-isle-of-the-twelve', 'The Isle of the Twelve', 'landmark', ARRAY['Island/Ruins']::text[], NULL, NULL, '<p>The ruins are the remains of an ancient temple dedicated to twelve powerful beings known simply as "The Twelve." The Keepers were said to possess the ability to control the seasons and maintain the balance of nature. Their powers were feared and envied, and they were eventually overthrown and their temple destroyed.</p>');
-- legacy locations/mnht7nuifgs54mhyl7e
insert into locations (id, campaign_id, region_id, slug, name, type, tags, controlled_by_faction_id, atmosphere, content_html) values ('ec0207f6-823f-4787-8a3d-0f23a2b245c8', '3d94bb9a-3995-452f-9e20-371c6c697443', '58cf07dc-2412-4da0-8511-ec2619af17b2', 'underoot', 'Underoot', 'settlement', ARRAY['Refuge']::text[], 'f1940563-820e-443d-a54a-9b48c6ba3c44', NULL, '<p>An underground city beneath Rot Hollow. The home of the resistance but also serves as a settlement for refugees. It is uncertain how many Wicklings live here but the number is likely in the thousands.</p><h3>Points of Interest</h3><p><strong>Residential Cavern (Main Chamber)</strong><br>Largest of the caverns in the Underoot the cave floor is covered in stalagmites and pools of water. In the center of the chamber is a Shanty town type area built on to of a wooden platform. Around the sides of the cavern are many dwellings built into the side of the cave walls. The dwellings continue up the sides until the cave wall inverts too much.Mossheart''s Grove<br>Large tree growing out of one of the pools on the Residential Cavern''s floor. Elder Mossheart Frequently communes with nature here and meditates. While she meditates she surrounds herself with many spores.</p><p><strong>Agricultural Cavern</strong><br>This chamber is lit by natural light that comes in from the cavern ceiling. A series of mirrors have been assembled to amplify the natural light in this chamber. The resistance grows all of the food to support its residents and fighters. There also is a large section for growing both medicinal and toxic herbs. The toxic herbs are handled very carefully with many protocols to make sure they don''t contaminate any other areas.</p><p><strong>War Chamber</strong><br>There is a large stone table top in the center of the chamber built on top of a series of stalagmites. On the table is a few rolled up maps on top of an unrolled one. There are markers spread out around the map to symbolize Fanewick and Haven forces.</p><p><strong>Medical Hub</strong><br>The medical hub is full of many beds with injured and sick. There is a large supply of medicinal herbs on shelves along the walls. Many stalagmites create natural separations to line the beds. </p>');

-- legacy npcs/mmlf395c1b7xah6bteq
