insert into characters (id, campaign_id, slug, name, kind, role_or_title, tags, faction_id, home_location_id, attitude, vitality, appearance, personality, content_html) values ('1fea7721-6ff4-4f92-90e1-325250983878', '3d94bb9a-3995-452f-9e20-371c6c697443', 'mugsy', 'Mugsy', 'npc', 'Firbolg Barkeep', '{}', null, NULL, 'ally', 'alive', 'Mugsy is a stout firbolg woman who was the runt of her family. She has an almost dwarven face but her ears droop down to the side. She has long hair with two thick breads coming down, one over each shoulder.', 'She is aggressive when she needs to be but has a southern hospitality warmth to her.', '<p>Frequently found at: Treetop Tavern</p>');
