insert into characters (id, campaign_id, slug, name, kind, role_or_title, tags, faction_id, home_location_id, attitude, vitality, appearance, personality, content_html) values ('e6856eed-adf0-42b9-b25f-a06396cebb4d', '3d94bb9a-3995-452f-9e20-371c6c697443', 'ronan', 'Ronan', 'npc', 'Simiah Ranger', '{}', 'f1940563-820e-443d-a54a-9b48c6ba3c44', NULL, 'ally', 'alive', 'Ronan is a medium sized (5ft tall) Simiah in a hooded cloak. His wolf companion, Snaggletooth, is always at his feet. Snaggletooth is very protective of Ronan. ', 'Mysterious and a bit antisocial. He comes off a bit abrasive but is eager to find allies in his fight against Haven.', NULL);
