insert into characters (id, campaign_id, slug, name, kind, role_or_title, tags, faction_id, home_location_id, attitude, vitality, appearance, personality, content_html) values ('df261fb1-de8a-4cd6-857c-4f593b84956b', '3d94bb9a-3995-452f-9e20-371c6c697443', 'commander-thessa-ironbark', 'Commander Thessa Ironbark', 'npc', 'Orc Commander', '{}', 'f1940563-820e-443d-a54a-9b48c6ba3c44', 'ec0207f6-823f-4787-8a3d-0f23a2b245c8', 'ally', 'alive', 'Muscular orc woman missing her left arm. She wears a prosthetic clank arm in its place.', 'Thessa grew up as a farmer to the south of The Riverwalkers Hunting Ground. Her village and farm were attacked and taken by Havenite forces claiming land for their flower fields. Her parents and sister were killed in front of her while she helplessly hid under a wooden cart, too young to fight back.

She was taken in by another family of refugees. Because of the Haven occupation of villages and settlements closer to the border they moved into the less desirable rocky lands surrounding the Rot Hollow mountains.

She grew up hating Haven for what it stole from her, a life with her family and everything they worked so hard for. She has dedicated her life to bringing them down.', NULL);
