insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('ac6c9c24-10b5-4766-a025-51ea1bf486e1', '3d94bb9a-3995-452f-9e20-371c6c697443', 'journey-to-the-resistance', 'Journey to the Resistance', 'main', 'complete', 'e6856eed-adf0-42b9-b25f-a06396cebb4d', null, 'Ronan left a note with Mugsy at the Treetop Tavern inviting the party to meet him in the woods to the northwest. He instructed them to bring Nora along.', NULL, NULL, 'You left Alula with Nora and travelled towards the split oak to meet Ronan.
N''Lirk grewa large stalk to help climb the cliffs near fire falls.
At the top of the cliff you found an abandoned campsite and encountered 2 stonewraith''s', '{}');
