insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('d42b52ae-9883-4e3f-9a52-5ca4208e97f7', '3d94bb9a-3995-452f-9e20-371c6c697443', 'the-heart-in-the-bog', 'The Heart in the Bog', 'main', 'complete', 'c1449830-d1c3-4295-9f66-e7a0c341352b', NULL, 'Mirek, the Bandit leader, tells the party that The Fanewraith was headed to the Bogs of Despair to find a piece of Shun''Aush''s heart. The heart fragments are rumored to have unique magical properties to them. Her plan is to combine the magical properties from the heart with the rune essence that the bandits were mining.', 'Stop The Fanewraith from combining the rune essence with the magic from the heart fragments.', NULL, 'Complete, players successfully stopped the Fanewraith. She quickly and easily overpowered them by suspending them in the air. Unable to move, Nora joined the fight and distracted the Fanewraith long enough for her to drop them. While Nora checked on the party the Fanewraith was able to escape.', '{}');
-- legacy quests/mmm605xtbp1wfv9bfej
insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('63c652ce-d3b3-4a5a-abc1-ca368657d12a', '3d94bb9a-3995-452f-9e20-371c6c697443', 'yin-s-poison', 'Yin''s Poison', 'side', 'active', NULL, null, 'Yin asked N''Lirk for help in crafting a poison for her to use against her brother, Yang.', 'Collect Ingredients from:
• Bogs of Despair - Belladonna Black Adder Venom from Black Lotus 
• Fields of Unceasing - Whistling Thresh Feet
• Carnivorous Divide - Blood vine Nectar', NULL, '• Bogs of Despair - Belladonna Black Adder Venom from Black Lotus - COLLECTED', '{}');
-- legacy quests/mmm660sl2qscrecvzcz
insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('2d3d0688-2f5e-4fab-9b41-30d6cf2f0968', '3d94bb9a-3995-452f-9e20-371c6c697443', 'the-stone-cipher', 'The Stone Cipher', 'side', 'active', '3c53a242-9b04-41f3-bf6f-5e39d22779fb', 'c304fc10-2959-43a2-b955-997abff9c3a1', 'Elara believes that an ancient code, known as the "Stone Cipher," is hidden somewhere in the Unsleeping Wood. She believes it holds the location of a powerful ward that keeps the Witherwild back. She wants to use it to protect merchants moving in and out of the village', NULL, NULL, NULL, '{}');
-- legacy quests/mmm67xq2v9d5raxkr2k
insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('7aba75eb-4051-43ed-bbfb-b345bc50135f', '3d94bb9a-3995-452f-9e20-371c6c697443', 'hunt-for-the-great-stag', 'Hunt for the Great Stag', 'side', 'complete', 'e6856eed-adf0-42b9-b25f-a06396cebb4d', NULL, 'A massive Great Stag, far larger and more ferocious than any he''s ever seen, has been preying on the local wildlife and even attacking travelers. The Stag leaves a trail of destruction, spreading Witherwild corruption in its wake.', 'Return the antlers from the Great Stag to Ronan.', NULL, 'Completed, Ronan took the antlers. He was unhappy with Bunt for putting a leash on Snaggletooth during the quest. Eventually Snaggletooth seemed to forgive Bunt but was still annoyed.', '{}');
-- legacy quests/mmm6dmt8hzgy52yhhs8
insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('d4ac6047-d843-478a-ab93-226dce7512e8', '3d94bb9a-3995-452f-9e20-371c6c697443', 'fire-falls-bandit-hideout', 'Fire Falls Bandit Hideout', 'main', 'complete', '1fea7721-6ff4-4f92-90e1-325250983878', NULL, 'Mugsy reveals a location near the Fire Falls cliffside where Jagged Knife bandits loyal to the Fanewraith are known to gather. They are disrupting trade, harassing travelers, and stealing supplies.', NULL, NULL, 'Completed, players defeated all the bandits and made their way into the cave hideout. At the end of the cave they met Mirek who pointed them to the Bogs of Despair to stop the Fanewraith. 

The players decided to let Mirek go.', '{}');
-- legacy quests/mnhyi47p4sxideicmn8
insert into quests (id, campaign_id, slug, name, quest_type, status, giver_character_id, location_id, hook, objective, reward, progress, tags) values ('46e4b615-24a7-4335-8221-4bb5410efaef', '3d94bb9a-3995-452f-9e20-371c6c697443', 'flower-field-on-fire', 'Flower Field on Fire', 'main', 'active', 'df261fb1-de8a-4cd6-857c-4f593b84956b', 'ec0207f6-823f-4787-8a3d-0f23a2b245c8', '- The party heard of others attacking flower fields unsuccessfully. They want to help. Commander Thessa needed some time to think about the best field to attack to cause the most damage to Haven''s forces.', 'Destroy the flower field on the east side of The Riverwalkers Hunting Ground.', NULL, NULL, '{}');

-- legacy sessions/mmnl30tpn3ljb0zam7s
insert into sessions (id, campaign_id, slug, session_number, session_date, name, location_id, is_published, summary_html, highlights) values ('b9d0b926-cab9-428c-bdfe-fc4133a20625', '3d94bb9a-3995-452f-9e20-371c6c697443', 'heart-in-the-bog', 6, '2026-02-12', 'Heart in the Bog', NULL, false, '<p>• The party travelled to the Bogs of Despair to stop the Fanewraith from obtaining a piece of Shun''Aush''s heart. She was going to use it to craft an amulet that can be used to "weaken a god". <br>• You all fought your way through the bog full of a group of assassins hired to protect the Fanewraith while she obtained the heart fragment and performed a ritual to create the amulet.<br>• Nora showed up while you were incapacitated by the strength of the Fanewraith''s magic and saved you.<br>•  After the battle you collected the ingredients that the Fanewraith left behind when she fled and returned to Alula.<br>• Back at Alula you recieved a written message from Ronan left with Mugsy. He invited you to meet the resistance but gave you directions to a meeting spot rather than the hideout to be sure you aren''t followed. He also asked you to bring Nora with you.</p>', ARRAY['During the fight with the Fanewraith she captured you in a spell that restrained you completely and levitated you in the air. Unable to move, and at times even breathe, she spoke with you about the corruption of Haven. She also spoke about her plans briefly. She wants to steal the Sowing Eye from Nikta to end the overgrowth that is causing the Witherwild.','When all hope seemed to have been lost Nora ran through the bog and smashed into the Fanewraith with her shield. This caused her spell to relent and you crashed to the ground. While Nora was distracted making sure that you were ok the Fanewraith vanished, leaving behind the heart fragment she had found.']::text[]);
insert into session_gm_notes (session_id, cliffhanger, quest_progress_notes) values ('b9d0b926-cab9-428c-bdfe-fc4133a20625', '• You know the Fanewraith''s general plans but unsure where she disappeared to.
• Upon returning to Alula, Mugsy gave you a note from Ronan inviting you to meet the resistance.', '• You thwarted the Fanewraiths plan to craft the god-weakening amulet by stopping her from obtaining a heart fragment.');
insert into session_npcs (session_id, character_id) values ('b9d0b926-cab9-428c-bdfe-fc4133a20625', '021aa298-175d-4fb2-af1c-c37eb8205922');
insert into session_npcs (session_id, character_id) values ('b9d0b926-cab9-428c-bdfe-fc4133a20625', 'b422b896-2ae6-4169-a358-a32a54d03e3d');
