insert into sessions (id, campaign_id, slug, session_number, session_date, name, location_id, is_published, summary_html, highlights) values ('3b27f78c-1097-4ee4-8389-471956268941', '3d94bb9a-3995-452f-9e20-371c6c697443', 'journey-to-the-resistance-part-1', 7, '2026-03-12', 'Journey to the Resistance - Part 1', NULL, false, '<p>- You left Alula with Nora and travelled towards the split oak to meet Ronan.<br>- N''Lirk grewa large stalk to help climb the cliffs near fire falls.<br>- At the top of the cliff you found an abandoned campsite and encountered 2 stonewraith''s</p>', ARRAY['N''Lirk grew a large stalk to help the party climb a cliff','Stonewraiths are being spotted far outside of the mountainous areas they normally reside']::text[]);
insert into session_npcs (session_id, character_id) values ('3b27f78c-1097-4ee4-8389-471956268941', '1fea7721-6ff4-4f92-90e1-325250983878');
insert into session_npcs (session_id, character_id) values ('3b27f78c-1097-4ee4-8389-471956268941', 'b422b896-2ae6-4169-a358-a32a54d03e3d');
-- legacy sessions/mnhyevozgs3jj13lpp
insert into sessions (id, campaign_id, slug, session_number, session_date, name, location_id, is_published, summary_html, highlights) values ('5f4abee6-988f-4c01-8147-adf757294f9b', '3d94bb9a-3995-452f-9e20-371c6c697443', 'journey-to-the-resistance-part-2', 8, '2026-03-19', 'Journey to the Resistance - Part 2', 'ec0207f6-823f-4787-8a3d-0f23a2b245c8', false, '<p>- The party finished their rest at the abandoned camp after fighting the stonewraiths to the sound of war horns in the distance.<br>- Ronan came running out of the woods instructing them to follow him.<br>- The party followed him into a chase scene. With the Haven soldiers surrounding them in the woods they succeeded against every challenge.<br>- Eventually they made it to a vine covered cliff face that Ronan pulled aside to reveal a crack in the stone. It was just wide enough for everyone to fit through.<br>- Once inside Ronan explained the layout of the cave system and led them to The Grotto, a tavern in the center of the large cavern. There they met Commander Thessa Ironbark, Kael Dustborn, and Elder Mossheart.<br>- After filling the three new NPCs in on the war horns and Haven movements they went to the War Chamber<br>- They spoke about plans of what to do. The party suggested attacking a flower field and the Commander agreed.</p>', ARRAY['N''Lirk and Herbtle visited Elder Mosshearts Grove and meditated with her. N''Lirk was able to commune with her and the tree there.','Bunt and Yin went back to The Grotto and ordered some drinks. They over heard talks about the flower field. Bunt challenged an orc patron to a drinking contest and won.']::text[]);
insert into session_gm_notes (session_id, cliffhanger, quest_progress_notes) values ('5f4abee6-988f-4c01-8147-adf757294f9b', 'Commander Thessa retired to her chambers to think about the next move. Which flower field would hurt Haven the most to lose.', NULL);
insert into session_npcs (session_id, character_id) values ('5f4abee6-988f-4c01-8147-adf757294f9b', 'df261fb1-de8a-4cd6-857c-4f593b84956b');
insert into session_npcs (session_id, character_id) values ('5f4abee6-988f-4c01-8147-adf757294f9b', '4bdd9e96-d36c-4d74-83b2-c350666a4887');
insert into session_npcs (session_id, character_id) values ('5f4abee6-988f-4c01-8147-adf757294f9b', '05f740b8-37b5-46ba-8d04-bf0b3b22031f');
insert into session_npcs (session_id, character_id) values ('5f4abee6-988f-4c01-8147-adf757294f9b', 'e6856eed-adf0-42b9-b25f-a06396cebb4d');
-- legacy sessions/mnj5ayjv2fecv2h63wi
insert into sessions (id, campaign_id, slug, session_number, session_date, name, location_id, is_published, summary_html, highlights) values ('1b44f34d-f488-4862-b1e3-13a494ea99ff', '3d94bb9a-3995-452f-9e20-371c6c697443', 'burn-the-flower-field', 9, '2026-04-02', 'Burn the Flower Field', 'f38213a5-05f0-4120-9b0e-fc156b3f69aa', false, '<p>- Tired from trip to Underoot the party slept until the late evening<br>- After waking up Bunt took a moment to rally his friends and get them perepared for the day by singing a song<br>- N''lirk spoke to the ancient spirits to get a sense of what the day had in store for them. He saw the greenhouse exploding from barrels marked as explosives and two sets of guards patrolling the area outside<br>- They stepped out to the platform outside of their dwelling and made their way to The Grotto in the center of the Main Chamber of Underoot.<br>- In the tavern they heard people talking of their experiences and ideas about some of the flower fields. Giving them ideas of how best to handle the task ahead of them<br>- After ordering drinks and spending some time relaxing in the tavern, Commander Thessa came in and ushered them to the War Chamber.<br>- In the War Chamber Ronan and Kael waited for them.<br>- They spoke to the group about the plan.<br>- Commander Thessa expressed concerns that Haven may be developing a weapon with the white flowers from the flower field.<br>- Kael shared a rumor that the white flowers can be used to create a potion capable of collecting large amounts of stone dust.<br>- Commander Thessa''s concern is that a biological weapon could be created that would turn entire villages to stone.<br>- With a partial plan created Ronan handed out torches and the party set out for the flower field<br>- The party arrived at the flower field and decided that Bunt would gather up the patrolling guards into the greenhouse to distract them from seeing N''lirk and Herbtle approaching the guard tower.<br>- Bunt successfully convinced them that they should join him in the greenhouse for a celebration.<br>- While in the greenhouse N''lirk and Bunt snuck around the flower fields to the base of the guard tower.<br>- N''lirk destroyed the support beams holding up the structure with his fire flies to bring the tower crashing down.<br>- Herbtle set fire to one of the flower fields shortly after using a fire spell that he knows.<br>- During that time Bunt was able to get free of the greenhouse and send his phantom hand towards the explosive barrels with a torch.<br>- The greenhouse exploded killing all of the guards inside.<br>- The loud explosion alerted one of the guard captains who came to investigate. Upon arriving he saw Herbtle and N''lirk near the collapsed guard tower and attacked.<br>- Bunt took the time to try and take out the supply shed.<br>- There was another guard captain inside the shed. When Bunt attempted to burn it down, the guard came bursting out of the door knowing something was up. He saw Buntand attacked.<br>- N''lirk and Herbtle successfully fought off the guard captain they encountered.<br>- During this time another guard captain and the Field Overseer arrived. Upon seeing the chaos he set off the alarm and the area was flooded with guards. The Field Overseer charged towards N''lirk and Herbtle attacking Herbtle with a large battle axe.<br>- With all the large amount of guards swarming the area N''lirk and Herbtle decided it was time to retreat. Their mission was just about complete.<br>- Bunt traded a few more blows with the guard captain while N''lirk and Herbtle made their way to him.<br>- The fire from the greenhouse was spreading fast and jumped to the remaining flower field.<br>- The party was able to escape the field leaving the guards scrambling to save whatever remained.</p>', ARRAY['N''lirk communed with the ancient spirits to get a vision of the events for the day. He saw the greenhouse exploding and the patrolling guards.','Bunt convinced the guards to join him in the greenhouse where he then blew up the building killing them all.']::text[]);

-- legacy shattered_lands/mmsftrch1epbq6vx157
